#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define a struct to store session data
struct Session {
    char* user_id;
    char* session_id;
    int expiration_time;
};

// Create a cache for storing sessions
struct Cache {
    struct Session* sessions[10]; // maximum 10 sessions in the cache
    int num_sessions; // number of active sessions in the cache
};

void create_session(struct Cache* cache, char* user_id, char* session_id) {
    // Check if the cache is full
    if (cache->num_sessions == 10) {
        return; // Cannot create a new session if the cache is full
    }

    // Create a new session
    struct Session* new_session = malloc(sizeof(struct Session));
    new_session->user_id = user_id;
    new_session->session_id = session_id;
    new_session->expiration_time = get_current_time() + SESSION_TIMEOUT; // Set the expiration time for 10 minutes

    // Add the new session to the cache
    cache->sessions[cache->num_sessions++] = new_session;
}

void access_session(struct Cache* cache, char* user_id) {
    // Search for the specified user ID in the cache
    int i;
    for (i = 0; i < cache->num_sessions; i++) {
        if (strcmp(cache->sessions[i]->user_id, user_id) == 0) {
            break; // Found the specified user ID in the cache
        }
    }

    // Check if the user ID was found in the cache
    if (i < cache->num_sessions) {
        // Update the expiration time of the session
        cache->sessions[i]->expiration_time = get_current_time() + SESSION_TIMEOUT;
        return; // User ID was found, update the expiration time and return
    }

    // User ID was not found in the cache, create a new session
    create_session(cache, user_id);
}

void invalidate_session(struct Cache* cache, char* user_id) {
    // Search for the specified user ID in the cache
    int i;
    for (i = 0; i < cache->num_sessions; i++) {
        if (strcmp(cache->sessions[i]->user_id, user_id) == 0) {
            break; // Found the specified user ID in the cache
        }
    }

    // Check if the user ID was found in the cache
    if (i < cache->num_sessions) {
        free(cache->sessions[i]); // Free the memory of the session
        memmove(&cache->sessions[i], &cache->sessions[i + 1], sizeof(struct Session*) * (cache->num_sessions - i - 1));
        cache->num_sessions--; // Decrease the number of active sessions in the cache
    }
}

// Function to get the current time
